    const n = words.length;
    const answer: number[] = new Array(n).fill(0);

    // Preprocess to find the longest common prefix between all pairs of words
    const lcp = new Array(n).fill(0);

    // Build a trie to find the longest common prefix between words
    class TrieNode {
        children: Map<string, TrieNode>;
        constructor() {
            this.children = new Map();
        }
    }

    const root = new TrieNode();

    // Insert all words into the trie
    for (let i = 0; i < n; i++) {
        let node = root;
        for (const c of words[i]) {
            if (!node.children.has(c)) {
                node.children.set(c, new TrieNode());
            }
            node = node.children.get(c)!;
        }
    }

    // For each word, find the longest common prefix with the next word
    for (let i = 0; i < n - 1; i++) {
        let node = root;
        let len = 0;
        for (let j = 0; j < Math.min(words[i].length, words[i + 1].length); j++) {
            const c1 = words[i][j];
            const c2 = words[i + 1][j];
            if (c1 !== c2) break;
            if (node.children.has(c1)) {
                node = node.children.get(c1)!;
                len++;
            } else {
                break;
            }
        }
        lcp[i] = len;
    }

    // For each index i, calculate the answer by checking the longest common prefix
    // between words[i-1] and words[i], and between words[i] and words[i+1]
    for (let i = 0; i < n; i++) {
        let maxLen = 0;
        if (i > 0) {
            maxLen = Math.max(maxLen, lcp[i - 1]);
        }
        if (i < n - 1) {
            maxLen = Math.max(maxLen, lcp[i]);
        }
        answer[i] = maxLen;
    }

    return answer;
}

